import React, { Suspense, useCallback } from "react";
import { useDispatch, useSelector } from "react-redux";
import Sidebar from "./components/sidebar/Sidebar";
import Topbar from "./components/topbar/Topbar";
import "./App.css";
import Home from "./pages/home/Home";
import { BrowserRouter as Router, Routes, Route, Navigate } from "react-router-dom";
import UserList from "./pages/userList/UserList";
import User from "./pages/user/User";
import NewUser from "./pages/newUser/NewUser";
import ProductList from "./pages/productList/ProductList";
import Product from "./pages/product/Product";
import NewProduct from "./pages/newProduct/NewProduct";
import Login from "./pages/login/Login";
import Sales from "./pages/sales/Sales";
import { admin, userRequest } from "./requestMethods";
import OrderList from "./pages/orderList/OrderList";
import { logout, refreshAccessToken } from "./redux/apiCalls";
import jwt_decode from "jwt-decode";


console.log(admin)

const App = () => {
  const user = useSelector(state => state.user.currentUser);
  const dispatch = useDispatch();

  const logOut = useCallback(() => {
    dispatch(logout());
  }, [dispatch]);

  userRequest.interceptors.request.use(async (config) => {
    const accessToken = config.headers.token?.substring(7);
    console.log("accessToken => ", accessToken);
    let currentDate = new Date();
    const decodedToken = accessToken && jwt_decode(accessToken);
    if (decodedToken.exp * 1000 < currentDate.getTime()) {
      const data = await refreshAccessToken(dispatch, user.refreshToken, user.refreshTokenId);
      config.headers["token"] = "Bearer " + data.newAccessToken;
      console.log("newAccessToken => ", data.newAccessToken);
    }
    return config;
  }, (error) => {
    return Promise.reject(error)
  });

  return (
    <Suspense fallback={<div>Loading...</div>}>
      <Router>
        <Topbar />
        <div className="container">
          {admin && <Sidebar />}
          <Routes>
            <Route path="/login" element={<Login />} />
            {admin && (
              <>
                  <Route exact path="/" element={<Home />} />
                  <Route path="/orders" element={<OrderList />} />
                  <Route path="/users" element={<UserList />} />
                  <Route path="/user/:userId" element={<User />} />
                  <Route path="/newUser" element={<NewUser />} />
                  <Route path="/products" element={<ProductList />} />
                  <Route path="/product/:productId" element={<Product />} />
                  <Route path="/newproduct" element={<NewProduct />} />
                  <Route path="/sales" element={<Sales />} />
              </>
            )}
          </Routes>
          {!admin && <Navigate to="/login" />}
        </div>
      </Router>
    </Suspense>
  );
}

export default App;
